module ADD32
  (output reg signed [31:0] ERR_S,
   input signed [31:0] A,
   input signed [31:0] B,
   input C,    // Clock
   input CE,   // Clock Enable
   input R     // Synchronous Reset
   );

   always @(posedge C)
     if(R)
       ERR_S <= 32'sd0;
     else if(CE)
       ERR_S <= A + B;

endmodule
